parameters.jsonBody:
={
  "type": "message",
  "attachments": [
    {
      "contentType": "application/vnd.microsoft.card.adaptive",
      "content": {
        "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
        "type": "AdaptiveCard",
        "version": "1.4",
        "body": [
          { "type": "TextBlock", "size": "Large", "weight": "Bolder", "color": "Attention", "text": "⚠️ Zertifikat/Secret läuft bald ab" },
          { "type": "TextBlock", "wrap": true, "text": "{{ $json.body.count }} Eintrag/Einträge gefunden (Quelle: {{ $json.body.source }})." },
          { "type": "FactSet", "facts": [
            { "title": "App", "value": "{{ $json.body.items[0].App }}" },
            { "title": "Typ", "value": "{{ $json.body.items[0].Credential }}" },
            { "title": "Name", "value": "{{ $json.body.items[0].Name }}" },
            { "title": "Endet am", "value": "{{ $json.body.items[0].EndetAm }}" },
            { "title": "Tage übrig", "value": "{{ $json.body.items[0].TageRestlich }}" }
          ]}
        ]
      }
    }
  ]
}
